import sys
from typing import List

class Solution:
    def solve(self, V: int, E: int, edges: List[List[int]]) -> List[List[int]]:
        adj_list = [[] for _ in range(V)]
        for u, v in edges:
            adj_list[u].append(v)
            adj_list[v].append(u)
        return [sorted(neighbors) for neighbors in adj_list]

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        V, E = int(next(it)), int(next(it))
        edges = [[int(next(it)), int(next(it))] for _ in range(E)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.solve(V, E, edges)
    print("\n".join(map(lambda x: str(x), ans)))

