#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> solve(int V, int E, vector<vector<int>>& edges) {
        vector<vector<int>> adj_list(V);
        for (auto& edge : edges) {
            int u = edge[0], v = edge[1];
            adj_list[u].push_back(v);
            adj_list[v].push_back(u);
        }
        for (auto& neighbors : adj_list) {
            sort(neighbors.begin(), neighbors.end());
        }
        return adj_list;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(2));
    for (auto& edge : edges) {
        cin >> edge[0] >> edge[1];
    }
    Solution sol;
    vector<vector<int>> ans = sol.solve(V, E, edges);
    for (const auto& neighbors : ans) {
        cout << '[';
        for (int i = 0; i < neighbors.size(); i++) {
            cout << neighbors[i];
            if (i != neighbors.size() - 1) {
                cout << ',' << ' ';
            }
        }
        cout << ']' << '\n';
    }
    return 0;
}
